/**
 * ReviewActionBar — Inline action buttons for reviewing insights.
 *
 * Actions:
 * - ✅ Confirm — immediately confirms the insight
 * - ✏️ Edit — opens inline edit text field, then saves
 * - ❌ Reject — opens reason text field, then rejects
 */

import React, { useState } from 'react';
import {
  Box,
  Button,
  TextField,
  IconButton,
  Tooltip,
  Collapse,
} from '@mui/material';
import CheckIcon from '@mui/icons-material/Check';
import EditIcon from '@mui/icons-material/Edit';
import CloseIcon from '@mui/icons-material/Close';

interface ReviewActionBarProps {
  insightId: string;
  onConfirm: (id: string) => void;
  onReject: (id: string, reason: string) => void;
  onEdit: (id: string, newContent: string) => void;
}

const ReviewActionBar: React.FC<ReviewActionBarProps> = ({
  insightId,
  onConfirm,
  onReject,
  onEdit,
}) => {
  const [editing, setEditing] = useState(false);
  const [editText, setEditText] = useState('');

  const [rejecting, setRejecting] = useState(false);
  const [rejectReason, setRejectReason] = useState('');

  const handleConfirm = () => {
    onConfirm(insightId);
  };

  const handleStartEdit = () => {
    setEditing(true);
    setRejecting(false);
    setEditText('');
  };

  const handleSaveEdit = () => {
    if (editText.trim()) {
      onEdit(insightId, editText.trim());
    }
    setEditing(false);
    setEditText('');
  };

  const handleCancelEdit = () => {
    setEditing(false);
    setEditText('');
  };

  const handleStartReject = () => {
    setRejecting(true);
    setEditing(false);
    setRejectReason('');
  };

  const handleSubmitReject = () => {
    if (rejectReason.trim()) {
      onReject(insightId, rejectReason.trim());
    }
    setRejecting(false);
    setRejectReason('');
  };

  const handleCancelReject = () => {
    setRejecting(false);
    setRejectReason('');
  };

  return (
    <Box sx={{ width: '100%' }}>
      {/* Action buttons */}
      <Box sx={{ display: 'flex', gap: 0.5, alignItems: 'center' }}>
        <Tooltip title="确认洞察">
          <Button
            size="small"
            variant="contained"
            color="success"
            startIcon={<CheckIcon />}
            onClick={handleConfirm}
            sx={{ fontSize: 12 }}
          >
            确认
          </Button>
        </Tooltip>
        <Tooltip title="编辑内容">
          <Button
            size="small"
            variant="outlined"
            startIcon={<EditIcon />}
            onClick={handleStartEdit}
            sx={{ fontSize: 12 }}
          >
            编辑
          </Button>
        </Tooltip>
        <Tooltip title="驳回洞察">
          <Button
            size="small"
            variant="outlined"
            color="error"
            startIcon={<CloseIcon />}
            onClick={handleStartReject}
            sx={{ fontSize: 12 }}
          >
            驳回
          </Button>
        </Tooltip>
      </Box>

      {/* Edit mode */}
      <Collapse in={editing}>
        <Box sx={{ mt: 1, display: 'flex', flexDirection: 'column', gap: 1 }}>
          <TextField
            size="small"
            multiline
            rows={3}
            placeholder="编辑洞察内容..."
            value={editText}
            onChange={(e) => setEditText(e.target.value)}
            fullWidth
            autoFocus
          />
          <Box sx={{ display: 'flex', gap: 1 }}>
            <Button size="small" variant="contained" onClick={handleSaveEdit} disabled={!editText.trim()}>
              保存编辑
            </Button>
            <Button size="small" variant="text" onClick={handleCancelEdit}>
              取消
            </Button>
          </Box>
        </Box>
      </Collapse>

      {/* Reject mode */}
      <Collapse in={rejecting}>
        <Box sx={{ mt: 1, display: 'flex', flexDirection: 'column', gap: 1 }}>
          <TextField
            size="small"
            placeholder="请输入驳回理由..."
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            fullWidth
            autoFocus
            helperText="驳回理由将记录在审核日志中"
          />
          <Box sx={{ display: 'flex', gap: 1 }}>
            <Button
              size="small"
              variant="contained"
              color="error"
              onClick={handleSubmitReject}
              disabled={!rejectReason.trim()}
            >
              确认驳回
            </Button>
            <Button size="small" variant="text" onClick={handleCancelReject}>
              取消
            </Button>
          </Box>
        </Box>
      </Collapse>
    </Box>
  );
};

export default ReviewActionBar;
